mapper.select:
select count(1)
from logical_models
where model_code = #{modelCode}

    and id != #{excludeId}

mapper.insert:
insert into provider_model_mappings(
    logical_model_id, provider_id, model_id, provider_model_name, status, priority
) values (
    #{logicalModelId}, #{providerId}, #{modelId}, #{providerModelName}, #{status}, #{priority}
)

mapper.update:
update provider_model_mappings
set provider_id = #{providerId},
    model_id = #{modelId},
    provider_model_name = #{providerModelName},
    status = #{status},
    priority = #{priority}
where id = #{id}
  and logical_model_id = #{logicalModelId}

mapper.delete:
delete from provider_model_mappings
where id = #{mappingId}
  and logical_model_id = #{logicalModelId}
